1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Customer = { yearsWithMHPCO: number };
4	type Scenario = { customer: Customer; steps: QuoteStep[] };
5	type QuoteResult = { premium: number };
6	
7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_RATE = 0.1;
9	
10	const ITEM_BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const BLOCK_SIZE = 3;
20	const BLOCK_BASE_PREMIUM = 60;
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const CURSE_RATE = 0.5;
24	const HIGH_ENCHANTMENT_RATE = 0.3;
25	const HIGH_ENCHANTMENT_THRESHOLD = 5;
26	const LOYALTY_RATE = 0.2;
27	const LOYALTY_THRESHOLD_YEARS = 2;
28	
29	const sumBy = <T>(items: T[], f: (x: T) => number): number =>
30	  items.reduce((acc, x) => acc + f(x), 0);
31	
32	const baseFor = (item: Item): number => ITEM_BASE_PREMIUMS[item.type];
33	
34	const SURCHARGE_RULES: ReadonlyArray<{ applies: (item: Item) => boolean; rate: number }> = [
35	  { applies: (item) => item.cursed === true, rate: CURSE_RATE },
36	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_RATE },
37	];
38	
39	const surchargeFor = (item: Item): number => {
40	  const base = baseFor(item);
41	  return sumBy(SURCHARGE_RULES, (rule) => (rule.applies(item) ? base * rule.rate : 0));
42	};
43	
44	const totalSurchargeFor = (items: Item[]): number => sumBy(items, surchargeFor);
45	
46	const loyaltyDiscountFor = (customer: Customer, totalBase: number): number =>
47	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? totalBase * LOYALTY_RATE : 0;
48	
49	const premiumFor = (totalBase: number, totalSurcharge: number, customer: Customer): number =>
50	  totalBase
51	  + totalSurcharge
52	  + Math.ceil(totalBase * FIRST_INSURANCE_RATE)
53	  - loyaltyDiscountFor(customer, totalBase)
54	  + PROCESSING_FEE;
55	
56	const groupByType = (items: Item[]): Map<string, Item[]> => {
57	  const groups = new Map<string, Item[]>();
58	  for (const item of items) {
59	    const group = groups.get(item.type) ?? [];
60	    group.push(item);
61	    groups.set(item.type, group);
62	  }
63	  return groups;
64	};
65	
66	const formsCompleteBlock = (type: string, group: Item[]): boolean =>
67	  COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE;
68	
69	const baseForGroup = (type: string, group: Item[]): number =>
70	  formsCompleteBlock(type, group) ? BLOCK_BASE_PREMIUM : sumBy(group, baseFor);
71	
72	const totalBaseFor = (items: Item[]): number =>
73	  Array.from(groupByType(items)).reduce(
74	    (total, [type, group]) => total + baseForGroup(type, group),
75	    0,
76	  );
77	
78	const quoteFor = ({ items }: QuoteStep, customer: Customer): QuoteResult => ({
79	  premium: premiumFor(totalBaseFor(items), totalSurchargeFor(items), customer),
80	});
81	
82	export const processScenario = (input: Scenario): { results: QuoteResult[] } => {
83	  return { results: input.steps.map((step) => quoteFor(step, input.customer)) };
84	};
